func currencyOptionLabel(c money.Currency) string {
	switch c.Code {
	case money.SAT.Code:
		return "Satoshi (sats) — Bitcoin Lightning"
	case money.THB.Code:
		return "Thai Baht (฿)"
	default:
		return "US Dollar ($)"
	}
}

